def normalize_scores(scores: list[float], scale: float):
    total = sum(scores)
    if total == 0:
        return [0.0 for _ in scores]
    return [s / total * scale for s in scores]

def aggregate_results(results: list[float], threshold=0.5):
    filtered = [r for r in results if r > threshold]
